<?php
namespace App\Http\Controllers\Admin\Content;
use App\Domain\Admin\Content\RefinementContentService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\StoreRefinementLevelRequest;use App\Http\Requests\Admin\Content\StoreRefinementMaterialRequest;use App\Http\Requests\Admin\Content\UpdateRefinementLevelRequest;use App\Http\Requests\Admin\Content\UpdateRefinementMaterialRequest;use App\Models\Item;use App\Models\RefinementLevel;use App\Models\RefinementLevelMaterial;use App\Models\RefinementStatModifier;use InvalidArgumentException;
final class RefinementController extends Controller{public function index(){$modifiers=RefinementStatModifier::orderBy('refinement_level')->get()->keyBy('refinement_level');$statLevels=[];foreach(range(1,15) as $level){$modifier=$modifiers->get($level);$statLevels[]=['level'=>$level,'modifier'=>$modifier,'configured'=>(bool)$modifier,'active'=>$modifier&&$modifier->status==='active','percent'=>$modifier?round($modifier->stat_increase_basis_points/100,2):null];}return view('admin.content.refinement.index',['rules'=>RefinementLevel::with(['materials.item'])->orderBy('from_level')->get(),'materials'=>Item::where('is_stackable',true)->where('max_stack','>',1)->where('status','active')->orderBy('name')->get(),'statLevels'=>$statLevels]);}public function store(StoreRefinementLevelRequest $r,RefinementContentService $s){return$this->run(function()use($r,$s){$s->saveRule($r->validated());},'Regla creada.');}public function update(UpdateRefinementLevelRequest $r,RefinementLevel $refinementLevel,RefinementContentService $s){return$this->run(function()use($r,$s,$refinementLevel){$s->saveRule($r->validated(),$refinementLevel);},'Regla actualizada.');}public function destroy(RefinementLevel $refinementLevel,RefinementContentService $s){$s->deactivate($refinementLevel);return back()->with('status','Regla desactivada.');}public function storeMaterial(StoreRefinementMaterialRequest $r,RefinementLevel $refinementLevel,RefinementContentService $s){return$this->run(function()use($r,$s,$refinementLevel){$s->saveMaterial($refinementLevel,$r->validated());},'Material agregado.');}public function updateMaterial(UpdateRefinementMaterialRequest $r,RefinementLevel $refinementLevel,RefinementLevelMaterial $material,RefinementContentService $s){$this->assertLine($refinementLevel,$material);return$this->run(function()use($r,$s,$refinementLevel,$material){$s->saveMaterial($refinementLevel,$r->validated(),$material);},'Material actualizado.');}public function destroyMaterial(RefinementLevel $refinementLevel,RefinementLevelMaterial $material,RefinementContentService $s){$this->assertLine($refinementLevel,$material);$s->removeMaterial($material);return back()->with('status','Material retirado.');}private function assertLine($rule,$line){if((int)$line->refinement_level_id!==(int)$rule->id)abort(404);}private function run($callback,$message){try{$callback();return back()->with('status',$message);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}}
